/**
 * Migration script: Fix "maillage-interne-b2b" article in Sanity
 * - Converts markdown body → Portable Text blocks
 * - Fills missing required fields (date, description, category, author, draft)
 * - Fixes FAQ format (adds _key + _type)
 * - Removes autoGenerated flag
 *
 * Usage: node scripts/fix-maillage-article.mjs
 */

import { createClient } from "@sanity/client";
import dotenv from "dotenv";
import { randomBytes } from "crypto";

dotenv.config({ path: ".env.local" });

const client = createClient({
  projectId: "odavbqx4",
  dataset: "production",
  apiVersion: "2026-03-06",
  token: process.env.SANITY_API_TOKEN,
  useCdn: false,
});

const DOC_ID = "2lSJCEf1F4fyz387rCc0o4";

function makeKey() {
  return randomBytes(6).toString("hex");
}

// ---------------------------------------------------------------------------
// Markdown → Portable Text converter (covers h2-h4, paragraphs, bold,
// italic, links, bullet/numbered lists)
// ---------------------------------------------------------------------------

function markdownToPortableText(md) {
  const lines = md.split("\n");
  const blocks = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim() === "") {
      i++;
      continue;
    }

    // Headings
    const headingMatch = line.match(/^(#{2,4})\s+(.+)$/);
    if (headingMatch) {
      const level = headingMatch[1].length;
      blocks.push({
        _type: "block",
        _key: makeKey(),
        style: `h${level}`,
        markDefs: [],
        children: parseInline(headingMatch[2]),
      });
      i++;
      continue;
    }

    // Bullet list item
    const bulletMatch = line.match(/^(\s*)[-*]\s+(.+)$/);
    if (bulletMatch) {
      const indent = bulletMatch[1].length;
      const level = Math.floor(indent / 2) + 1;
      blocks.push({
        _type: "block",
        _key: makeKey(),
        style: "normal",
        listItem: "bullet",
        level,
        markDefs: [],
        children: parseInline(bulletMatch[2]),
      });
      i++;
      continue;
    }

    // Numbered list item
    const numMatch = line.match(/^(\s*)\d+[.)]\s+(.+)$/);
    if (numMatch) {
      const indent = numMatch[1].length;
      const level = Math.floor(indent / 2) + 1;
      blocks.push({
        _type: "block",
        _key: makeKey(),
        style: "normal",
        listItem: "number",
        level,
        markDefs: [],
        children: parseInline(numMatch[2]),
      });
      i++;
      continue;
    }

    // Skip H1 (already the title)
    if (line.match(/^#\s+/)) {
      i++;
      continue;
    }

    // Regular paragraph
    blocks.push({
      _type: "block",
      _key: makeKey(),
      style: "normal",
      markDefs: [],
      children: parseInline(line),
    });
    i++;
  }

  // Post-process: inject markDefs from children into parent blocks
  for (const block of blocks) {
    const defs = [];
    for (const child of block.children) {
      if (child._markDefs) {
        defs.push(...child._markDefs);
        delete child._markDefs;
      }
    }
    if (defs.length > 0) {
      block.markDefs = defs;
    }
  }

  return blocks;
}

/**
 * Parse inline markdown (bold, italic, links) into Portable Text spans
 */
function parseInline(text) {
  const spans = [];
  // Regex to match: **bold**, *italic*, [text](url)
  const regex = /(\*\*(.+?)\*\*|\*(.+?)\*|\[([^\]]+)\]\(([^)]+)\))/g;

  let lastIndex = 0;
  let match;

  while ((match = regex.exec(text)) !== null) {
    // Text before the match
    if (match.index > lastIndex) {
      const before = text.slice(lastIndex, match.index);
      if (before) {
        spans.push({
          _type: "span",
          _key: makeKey(),
          marks: [],
          text: before,
        });
      }
    }

    if (match[2]) {
      // Bold: **text**
      spans.push({
        _type: "span",
        _key: makeKey(),
        marks: ["strong"],
        text: match[2],
      });
    } else if (match[3]) {
      // Italic: *text*
      spans.push({
        _type: "span",
        _key: makeKey(),
        marks: ["em"],
        text: match[3],
      });
    } else if (match[4] && match[5]) {
      // Link: [text](url)
      const linkKey = makeKey();
      const span = {
        _type: "span",
        _key: makeKey(),
        marks: [linkKey],
        text: match[4],
        _markDefs: [{ _type: "link", _key: linkKey, href: match[5] }],
      };
      spans.push(span);
    }

    lastIndex = match.index + match[0].length;
  }

  // Remaining text
  if (lastIndex < text.length) {
    spans.push({
      _type: "span",
      _key: makeKey(),
      marks: [],
      text: text.slice(lastIndex),
    });
  }

  // If empty, add empty span
  if (spans.length === 0) {
    spans.push({
      _type: "span",
      _key: makeKey(),
      marks: [],
      text: text,
    });
  }

  return spans;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main() {
  console.log("Fetching article...");
  const doc = await client.fetch(
    `*[_id == $id][0]{body, faq, title}`,
    { id: DOC_ID }
  );

  if (!doc) {
    console.error("Article not found!");
    process.exit(1);
  }

  console.log(`Found: "${doc.title}"`);
  console.log(`Body type: ${typeof doc.body} (${doc.body.length} chars)`);
  console.log(`FAQ count: ${doc.faq?.length || 0}`);

  // 1. Convert markdown body → Portable Text
  const portableTextBody = markdownToPortableText(doc.body);
  console.log(`Converted to ${portableTextBody.length} Portable Text blocks`);

  // 2. Fix FAQ (add _type and _key)
  const fixedFaq = (doc.faq || []).map((item, idx) => ({
    _type: "faq",
    _key: `faq-${idx + 1}`,
    question: item.question,
    answer: item.answer,
  }));

  // 3. Build description from first paragraph
  const firstParagraph = doc.body.split("\n\n").find(
    (p) => p && !p.startsWith("#")
  );
  const description = firstParagraph
    ? firstParagraph.slice(0, 160).replace(/\*\*/g, "").trim()
    : "Guide complet du maillage interne B2B pour PME et ETI.";

  // 4. Patch the document
  console.log("\nPatching document...");
  const result = await client
    .patch(DOC_ID)
    .set({
      body: portableTextBody,
      faq: fixedFaq,
      description,
      date: "2026-03-21T00:00:00Z",
      author: "Lucas Gonzalez",
      category: "SEO",
      tags: ["maillage interne", "seo b2b", "stratégie de contenu", "référencement"],
      draft: false,
    })
    .unset(["autoGenerated"])
    .commit();

  console.log("Done! Document patched:", result._id);
  console.log("\nSummary:");
  console.log(`  - Body: ${portableTextBody.length} blocks (Portable Text)`);
  console.log(`  - FAQ: ${fixedFaq.length} items (with _type + _key)`);
  console.log(`  - Description: "${description.slice(0, 60)}..."`);
  console.log(`  - Date: 2026-03-21`);
  console.log(`  - Category: SEO`);
  console.log(`  - Author: Lucas Gonzalez`);
  console.log(`  - autoGenerated: removed`);
}

main().catch((err) => {
  console.error("Error:", err.message);
  process.exit(1);
});
